// agent.proto
service AgentService {
  rpc ExecuteTask(TaskRequest) returns (TaskResponse);
  rpc StreamProgress(TaskRequest) returns (stream ProgressUpdate);
}

message TaskRequest {
  string task_id = 1;
  string goal = 2;
}

message TaskResponse {
  string result = 1;
  bool success = 2;
}

message ProgressUpdate {
  string task_id = 1;
  string status = 2;
  int32 progress = 3;
}

response_stream = stub.StreamProgress(request)  # server streaming
for update in response_stream:
    print(f"Progress: {update.progress}%")

# producer.py (orchestrator)
import celery

celery_app = Celery("agent_swarm", broker="redis://localhost:6379/0")

@celery_app.task
def run_subagent(domain: str, task: dict):
    subagent = get_subagent_by_domain(domain)
    return subagent.invoke(task)

# Orchestrator dispatches tasks
for subtask in subtasks:
    run_subagent.send(subtask["domain"], subtask)  # enqueues to queue
# consumer.py (worker)
@celery_app.task(name="run_subagent")
def run_subagent(domain: str, task: dict):
    subagent = get_subagent_by_domain(domain)
    return subagent.invoke(task)
